def iv(v):
    try: return "NULL" if v is None or v=="" else str(int(v))
    except Exception: return "NULL"
def num(v):
    try: return "0" if v is None or v=="" else str(float(v))
    except Exception: return "0"
def bv(v):
    return "1" if str(v).lower() in ("1","true","yes","on") else "0"

TEXT={"title":"Title","slug":"Slug","summary":"Summary","description":"Description","category":"Category","level":"Level","instructor":"Instructor","coverColor":"CoverColor"}
if op=="list":
    w=["1=1"]
    q=d.get("q")
    if q:
        lk="'%"+str(q).replace("'","''")+"%'"
        w.append("(Title LIKE "+lk+" OR Summary LIKE "+lk+" OR Category LIKE "+lk+" OR Instructor LIKE "+lk+")")
    if d.get("category"): w.append("Category = "+s(d.get("category")))
    if d.get("level"): w.append("Level = "+s(d.get("level")))
    if d.get("published") not in (None,""): w.append("Published = "+bv(d.get("published")))
    take=iv(d.get("take")) if d.get("take") not in (None,"") else "200"
    skip=iv(d.get("skip")) if d.get("skip") not in (None,"") else "0"
    sort=d.get("sort") or "CreatedAt"
    if sort not in ("CreatedAt","UpdatedAt","Title","Category","Level","DurationHours"): sort="CreatedAt"
    dr="ASC" if str(d.get("dir") or "desc").lower()=="asc" else "DESC"
    return "SELECT c.*, (SELECT COUNT(*) FROM lessons l WHERE l.CourseId=c.Id) AS LessonCount, (SELECT COUNT(*) FROM enrollments e WHERE e.CourseId=c.Id) AS EnrollmentCount FROM courses c WHERE "+" AND ".join(w)+" ORDER BY "+sort+" "+dr+" LIMIT "+take+" OFFSET "+skip+";"
if op in ("get","detail"):
    cid=iv(d.get("id"))
    return "SELECT c.*, (SELECT COUNT(*) FROM lessons l WHERE l.CourseId=c.Id) AS LessonCount, (SELECT COUNT(*) FROM enrollments e WHERE e.CourseId=c.Id) AS EnrollmentCount FROM courses c WHERE c.Id="+cid+";"
if op=="create":
