    for k,c in TEXT.items():
        if k in d: cols.append(c);vals.append(s(d.get(k)))
    if "durationHours" in d: cols.append("DurationHours");vals.append(num(d.get("durationHours")))
    if "published" in d: cols.append("Published");vals.append(bv(d.get("published")))
    if not cols: return "SELECT 'no fields' AS Error;"
    return "INSERT INTO courses ("+", ".join(cols)+") VALUES ("+", ".join(vals)+"); SELECT * FROM courses WHERE Id=last_insert_rowid();"
if op=="update":
    cid=iv(d.get("id"));st=[]
    for k,c in TEXT.items():
        if k in d: st.append(c+" = "+s(d.get(k)))
    if "durationHours" in d: st.append("DurationHours = "+num(d.get("durationHours")))
    if "published" in d: st.append("Published = "+bv(d.get("published")))
    st.append("UpdatedAt = CURRENT_TIMESTAMP")
    return "UPDATE courses SET "+", ".join(st)+" WHERE Id="+cid+"; SELECT * FROM courses WHERE Id="+cid+";"
