    cid=iv(d.get("id"))
    return "DELETE FROM lessons WHERE CourseId="+cid+"; DELETE FROM courses WHERE Id="+cid+"; SELECT "+cid+" AS DeletedId;"
return "SELECT * FROM courses ORDER BY Id DESC LIMIT 200;"

